# Script para reescrever a página Sobre — troca link do LinkedIn na bio pelo link interno /coaching

if (-not (Test-Path "package.json")) {
    Write-Host "ERRO: Rode este script DENTRO da pasta do projeto (onde tem package.json)." -ForegroundColor Red
    exit 1
}

$sobreB64 = ""
$sobreBytes = [System.Convert]::FromBase64String($sobreB64)
[System.IO.File]::WriteAllBytes("$PWD\src\app\sobre\page.tsx", $sobreBytes)
Write-Host "Reescrito: src/app/sobre/page.tsx" -ForegroundColor Green

Write-Host ""
Write-Host "Pronto. Rode: git status" -ForegroundColor Cyan
